// Step 5 — COD branch (₹100 advance QR + switch-to-full handlers + qr ?amt support).
// GUARDED per-file swap: applies ONLY if your file matches the post-Step-4 original.
const fs=require('fs');const path=require('path');
function applyFile(rel, origB64, editB64){
  const FILE=path.join(__dirname, rel);
  const ORIG=Buffer.from(origB64,'base64').toString('utf8');
  const EDIT=Buffer.from(editB64,'base64').toString('utf8');
  const cur=fs.readFileSync(FILE,'utf8');
  if(cur===EDIT){console.log('⏭  '+rel+' already at Step 5. Skipped.');return;}
  if(cur!==ORIG){console.error('❌ '+rel+' differs from the expected Step-4 version — NOT modifying it. Send this line to Claude.');process.exitCode=1;return;}
  fs.writeFileSync(FILE,EDIT);
  console.log('✅ '+rel+' updated.');
}
applyFile("handlers/rajathee.js","","");
applyFile("routes/qr.js","","");
if(process.exitCode!==1) console.log('✅ Step 5 applied: COD branch + switch handlers + QR amount override.');
